```typescript
export interface OrderItem {
    price: number;
}

export interface Order {
    id: string | number;
    items: OrderItem[];
}

export interface User {
    id: string | number;
}

export interface ProcessOptions {
    discount?: number;
}

export interface ProcessedOrder {
    orderId: string | number;
    userId: string | number;
    items: (OrderItem & { finalPrice: number })[];
    total: number;
    processedAt: Date;
}

export interface ValidationResult {
    valid: boolean;
    error?: string;
}

export function processOrder(
    order: Order,
    user: User,
    options?: ProcessOptions
): ProcessedOrder {
    const discount = options?.discount || 0;
    const items = order.items.map((item) => ({
        ...item,
        finalPrice: item.price * (1 - discount),
    }));

    return {
        orderId: order.id,
        userId: user.id,
        items,
        total: items.reduce((sum, i) => sum + i.finalPrice, 0),
        processedAt: new Date(),
    };
}

export function validateOrder(order: Order): ValidationResult {
    if (!order.items || order.items.length === 0) {
        return { valid: false, error: "No items" };
    }
    if (order.items.some((i) => i.price < 0)) {
        return { valid: false, error: "Invalid price" };
    }
    return { valid: true };
}
```

