            name = mainFun.name!!
            settings.taskNames.add(jsRunTaskName)
            settings.externalProjectPath =
                ExternalSystemApiUtil.getExternalProjectPath(context.location?.module)
        }
        return true
    }

    companion object {
        private const val jsRunTaskName = "jsBrowserDevelopmentRun"
