                jstackOutput.splitToSequence("\n").forEach {
                    appendLine("> $it")
                }
            }
            process.destroyForcibly()
            error(message)
        }
        val exitCode = process.exitValue()
        check(exitCode == 0) { "Non-zero exit code: $exitCode" }
    }
}

